package com.cognizant.payment.controller;import com.cognizant.payment.service.PaymentService;import org.springframework.web.bind.annotation.*;import java.util.Map;@RestController public class PaymentController{private final PaymentService s;public PaymentController(PaymentService s){this.s=s;}@GetMapping("/payments")public Map pay(@RequestParam(defaultValue="0")long delay){return s.pay(delay);}}